// // This module shifts the input data to the right on the positive edge of the clock.
module shift_register (
    input clk,
    input reset,
    input data_in,
    output reg [3:0] q
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 4'b0000;
        else
            q <= {q[2:0], data_in};
    end

endmodule
